// Backwards compatibility rules — never break these:
// ✅ Adding optional fields to response
// ✅ Adding optional request parameters
// ✅ Adding new endpoints
// ❌ Removing or renaming fields
// ❌ Changing field types
// ❌ Making optional fields required

// 1. Define service in .proto
syntax = "proto3";
service OrderService {
  rpc GetOrder (GetOrderRequest) returns (Order);
  rpc StreamOrders (StreamRequest) returns (stream Order); // server streaming
}
message GetOrderRequest { int64 order_id = 1; }
message Order {
  int64 id = 1;
  string status = 2;
  double total = 3;
}

// 2. Generated Java server stub — implement the service
public class OrderServiceImpl extends OrderServiceGrpc.OrderServiceImplBase {
    @Override
    public void getOrder(GetOrderRequest req,
                         StreamObserver<Order> responseObserver) {
        Order order = orderRepository.findById(req.getOrderId());
        responseObserver.onNext(order);
        responseObserver.onCompleted();
    }
}

// 3. Generated client usage
OrderServiceGrpc.OrderServiceBlockingStub stub =
    OrderServiceGrpc.newBlockingStub(channel);
Order order = stub.getOrder(
    GetOrderRequest.newBuilder().setOrderId(42).build());

// Client queries only what it needs
query {
  user(id: 42) {
    name
    email
    orders(last: 5) {
      id
      total
    }
  }
}
// Returns exactly: name, email, and last 5 order ids+totals
// No extra fields, no extra round trips

// N+1 problem: naive resolver fetches orders for each user separately
// Fix with DataLoader (batches and caches fetches within a request)
@SchemaMapping
public CompletableFuture<List<Order>> orders(
        User user, DataLoader<Long, List<Order>> ordersLoader) {
    return ordersLoader.load(user.getId()); // batched — one DB query for all users
}

